// ==================== CST / CCLASSTRIB DATA ====================
// CST conforme IT RT 2025.002 - Informe Técnico oficial
// CClassTrib: código de 6 dígitos da classificação tributária oficial
// Alíquotas de teste 2026: CBS 0,9% + IBS 0,1% = 1,00%
// Alíquotas de referência final: CBS 8,8% + IBS 17,7% = 26,5%
//
// CST 000 = Tributação integral
// CST 200 = Alíquota reduzida (100%=zero, 60%, 40%, 30%)
// CST 400 = Isenção
// CST 410 = Imunidade e não incidência
// CST 550 = Suspensão
// CST 620 = Tributação monofásica

function _p(ncm,desc,cc){return{ncm,desc,cclass:cc,classif:'Tributação Integral',cst:'000',cbs:'0,90%',ibs:'0,10%',total:'1,00%',categ:'padrao'}}
function _r6(ncm,desc,cc){return{ncm,desc,cclass:cc,classif:'Alíquota Reduzida 60%',cst:'200',cbs:'0,36%',ibs:'0,04%',total:'0,40%',categ:'reduzida'}}
function _i(ncm,desc,cc,cl,cs){return{ncm,desc,cclass:cc,classif:cl||'Alíquota Zero — Cesta Básica Nacional',cst:cs||'200',cbs:'0,00%',ibs:'0,00%',total:'0,00%',categ:'isento'}}
function _m(ncm,desc,cc,un,tipo){return{ncm,desc,cclass:cc,classif:'Monofásico — '+(tipo||'Combustíveis'),cst:'620',cbs:'R$/'+un,ibs:'R$/'+un,total:'Fixa/'+un,categ:'monofasico'}}
function _s(ncm,desc,cc,tipo){return{ncm,desc,cclass:cc,classif:'Tributação Integral + Imposto Seletivo — '+tipo,cst:'000',cbs:'0,90%+IS',ibs:'0,10%+IS',total:'IVA+IS',categ:'seletivo'}}

